import React, { useEffect } from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";

const glassStyles = `
  .about-container {
    min-height: 100vh;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    padding: 60px 20px;
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  }

  .glass-header {
    background: rgba(255, 255, 255, 0.15);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.2);
    border-radius: 20px;
    padding: 50px;
    margin-bottom: 40px;
    box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.37);
    text-align: center;
    color: white;
    max-width: 1200px;
    margin-left: auto;
    margin-right: auto;
  }

  .glass-header h1 {
    font-size: 3em;
    margin: 0 0 20px 0;
    font-weight: 700;
    text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.2);
  }

  .glass-header p {
    font-size: 1.1em;
    line-height: 1.8;
    margin: 0;
    opacity: 0.95;
  }

  .glass-card {
    background: rgba(255, 255, 255, 0.1);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.2);
    border-radius: 15px;
    padding: 40px;
    margin-bottom: 30px;
    box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.37);
    color: white;
    max-width: 1200px;
    margin-left: auto;
    margin-right: auto;
  }

  .glass-card h2 {
    font-size: 2em;
    margin-top: 0;
    margin-bottom: 25px;
    font-weight: 600;
    border-bottom: 2px solid rgba(255, 255, 255, 0.3);
    padding-bottom: 15px;
  }

  .glass-card ul {
    list-style: none;
    padding: 0;
    margin: 0;
  }

  .glass-card li {
    padding: 10px 0 10px 30px;
    position: relative;
    font-size: 1.05em;
    line-height: 1.6;
  }

  .glass-card li:before {
    content: "✓";
    position: absolute;
    left: 0;
    color: #4ade80;
    font-weight: bold;
    font-size: 1.2em;
  }

  .feature-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 25px;
    margin-top: 20px;
  }

  .feature-item {
    background: rgba(255, 255, 255, 0.08);
    padding: 25px;
